// ════════════════════════════════════════════════════════
// STARLINK TRACKER — CONFIGURATION REFERENCE
// This node has no wires. It is documentation only.
// ════════════════════════════════════════════════════════
//
// 1. CACHE FILE PATH  (default: Docker /data/ mount)
//    Edit in: "Check Cache Age", "Save & Store TLE", "Load Cache Fallback"
//    Bare Node-RED example: '/home/pi/.node-red/starlink_cache.csv'
//
// 2. OBSERVER LOCATION
//    Set via Dashboard Settings page: http://<host>:1880/starlink/settings
//    Or edit the fallback in "Compute Satellite Positions":
//      flow.get('observer') || { lat: 51.0447, lon: -114.0719 }
//
// 3. PERSISTENT CONTEXT  (required for observer/favorites to survive restart)
//    Add to Node-RED settings.js:
//      contextStorage: {
//        default: { module: 'memory' },
//        file:    { module: 'localfilesystem' }
//      }
//
// 4. DASHBOARD PAGES
//    SVG Radar:    http://<host>:1880/starlink/svg-radar
//    Canvas Radar: http://<host>:1880/starlink/canvas-radar
//    Ground Track: http://<host>:1880/starlink/ground-track
//    Settings:     http://<host>:1880/starlink/settings
//
// 5. DATA SOURCE
//    Celestrak: https://celestrak.org/NORAD/elements/gp.php?GROUP=starlink&FORMAT=csv
//    Refreshed every 2h (rate limited). Cache saved to CACHE FILE PATH above.
//
// ════════════════════════════════════════════════════════
return null;

// Issue #5 perf: check 2h cache before fetching
const CACHE = '/data/starlink_tle_cache.csv';
const TWO_HOURS = 2 * 60 * 60 * 1000;
try {
    const stat = fs.statSync(CACHE);
    const age  = Date.now() - stat.mtimeMs;
    if (age < TWO_HOURS) {
        const data = fs.readFileSync(CACHE, 'utf8');
        global.set('rawStarlinkData', data);
        global.set('parsedSats', parseCsv(data));
        global.set('tleFetchedAt', stat.mtimeMs);
        global.set('satHistory', {});
        node.status({fill:'green', shape:'dot', text:`cache ${Math.round(age/60000)}m old`});
        return null;
    }
} catch(e) { /* no cache yet */ }
return msg;

function parseCsv(raw) {
    return raw.split('\n').slice(1).map(line => {
        const r = line.split(',');
        if (r.length < 9 || !r[0] || !r[0].startsWith('STARLINK')) return null;
        const n=+r[3], inc=+r[5], raan=+r[6], argp=+r[7], M0=+r[8];
        if ([n,inc,raan,argp,M0].some(isNaN)) return null;
        // Issue #1 fix: append Z so epoch is parsed as UTC, not local time
        const epoch = new Date(r[2].trim() + 'Z').getTime();
        if (!epoch || isNaN(epoch)) return null;
        return { name:r[0].trim(), n, inc, raan, argp, M0, epoch };
    }).filter(Boolean);
}

// Route HTTP result: success → port 1, error → port 2 (cache fallback)
if (msg.error || (msg.statusCode && msg.statusCode !== 200)) {
    node.warn('HTTP fetch failed (' + (msg.error || msg.statusCode) + ') — trying cache');
    return [null, msg];
}
return [msg, null];

// Issue #1, #5: Save TLE, parse once, store to global
const CACHE = '/data/starlink_tle_cache.csv';
const now = Date.now();
try { fs.writeFileSync(CACHE, msg.payload); } catch(e) { node.warn('Cache write failed: ' + e.message); }
global.set('rawStarlinkData', msg.payload);
global.set('parsedSats', parseCsv(msg.payload));
global.set('tleFetchedAt', now);
global.set('satHistory', {});
node.status({fill:'blue', shape:'dot', text:`fetched ${new Date(now).toLocaleTimeString()}`});
return null;

function parseCsv(raw) {
    return raw.split('\n').slice(1).map(line => {
        const r = line.split(',');
        if (r.length < 9 || !r[0] || !r[0].startsWith('STARLINK')) return null;
        const n=+r[3], inc=+r[5], raan=+r[6], argp=+r[7], M0=+r[8];
        if ([n,inc,raan,argp,M0].some(isNaN)) return null;
        // Issue #1 fix: append Z so epoch is parsed as UTC, not local time
        const epoch = new Date(r[2].trim() + 'Z').getTime();
        if (!epoch || isNaN(epoch)) return null;
        return { name:r[0].trim(), n, inc, raan, argp, M0, epoch };
    }).filter(Boolean);
}

// HTTP failed — load from cache file as fallback
const CACHE = '/data/starlink_tle_cache.csv';
try {
    const data = fs.readFileSync(CACHE, 'utf8');
    const stat = fs.statSync(CACHE);
    global.set('rawStarlinkData', data);
    global.set('parsedSats', parseCsv(data));
    global.set('tleFetchedAt', stat.mtimeMs);
    global.set('satHistory', {});
    node.status({fill:'yellow', shape:'ring', text:`HTTP err, using cache ${new Date().toLocaleTimeString()}`});
} catch(e) {
    node.error('HTTP fetch failed and no cache available: ' + e.message);
}
return null;

function parseCsv(raw) {
    return raw.split('\n').slice(1).map(line => {
        const r = line.split(',');
        if (r.length < 9 || !r[0] || !r[0].startsWith('STARLINK')) return null;
        const n=+r[3], inc=+r[5], raan=+r[6], argp=+r[7], M0=+r[8];
        if ([n,inc,raan,argp,M0].some(isNaN)) return null;
        // Issue #1 fix: append Z so epoch is parsed as UTC, not local time
        const epoch = new Date(r[2].trim() + 'Z').getTime();
        if (!epoch || isNaN(epoch)) return null;
        return { name:r[0].trim(), n, inc, raan, argp, M0, epoch };
    }).filter(Boolean);
}

// Issue #13: only pass message if at least one client is viewing
const viewers = global.get('viewerCount') || 0;
if (viewers > 0) return msg;
return null;

// Compute visible satellite positions — Issues #1 #2 #4 #5 #6 #8 #9 #10 #12
const deg2rad = Math.PI / 180;
const Re = 6371, h = 550;

// Issue #6: read observer from flow context (set via settings page), fallback to Calgary
const obs = flow.get('observer') || { lat: 51.0447, lon: -114.0719 };
const obs_lat = obs.lat * deg2rad;
const obs_lon = obs.lon * deg2rad;

// Issue #8: read filters from flow context
const minEl   = flow.get('minElevation') || 0;
const shells  = flow.get('activeShells') || [43, 53, 70, 97];
const maxSats = flow.get('maxSats') || 300;
const selectedSat = flow.get('selectedSat') || null;

// Issue #5: use pre-parsed array, not raw CSV
const parsedSats = global.get('parsedSats');
if (!parsedSats || parsedSats.length === 0) return null;

// Issue #10: TLE freshness
const tleFetchedAt = global.get('tleFetchedAt') || 0;

const now  = Date.now();
const GAST = (280.46061837 + 360.98564736629 * (now - 946728000000) / 86400000) % 360;

// Issue #12: sun position (simple solar declination + GAST hour angle)
const sunEl = computeSunElevation(now, obs.lat, obs.lon);
const observerDark = sunEl < -6; // astronomical twilight

let hist = global.get('satHistory') || {};
const sats = [];
const prevVis = global.get('prevVisible') || {};

for (const sat of parsedSats) {
    const { name, n, inc, raan, argp, M0, epoch } = sat;

    // Issue #8: shell filter
    const shell = inc < 50 ? 43 : inc < 60 ? 53 : inc < 75 ? 70 : 97;
    if (!shells.includes(shell)) continue;

    const M    = (M0 + n * (now - epoch) / 86400000 * 360) % 360;
    const u    = (argp + M) * deg2rad;
    const ir   = inc * deg2rad;
    const slat = Math.asin(Math.max(-1, Math.min(1, Math.sin(ir) * Math.sin(u))));
    // Issue #2 fix: normalize longitude to [-180, 180] properly
    let slon = ((raan + Math.atan2(Math.cos(ir)*Math.sin(u), Math.cos(u))/deg2rad) - GAST + 540) % 360 - 180;

    const dlon  = slon * deg2rad - obs_lon;
    const cos_c = Math.sin(obs_lat)*Math.sin(slat) + Math.cos(obs_lat)*Math.cos(slat)*Math.cos(dlon);
    if (cos_c < Re/(Re+h)) continue;
    const c  = Math.acos(Math.max(-1, Math.min(1, cos_c)));
    const el = Math.atan((cos_c - Re/(Re+h)) / Math.sin(c)) / deg2rad;
    if (el <= minEl) continue;  // Issue #8: min elevation filter

    const az = (Math.atan2(
        Math.sin(dlon)*Math.cos(slat),
        Math.cos(obs_lat)*Math.sin(slat) - Math.sin(obs_lat)*Math.cos(slat)*Math.cos(dlon)
    ) / deg2rad + 360) % 360;

    const lat = +(slat / deg2rad).toFixed(3);
    const lon = +slon.toFixed(3);

    if (!hist[name]) hist[name] = [];
    hist[name].push({t:now, el:+el.toFixed(2), az:+az.toFixed(2), lat, lon});
    hist[name] = hist[name].filter(p => (now - p.t) < 60000).slice(-20);

    // Issue #12: illumination check
    const illuminated = isSatIlluminated(lat, lon, now);

    sats.push({
        name, inc: +inc.toFixed(1), el: +el.toFixed(2), az: +az.toFixed(2),
        lat, lon, trail: hist[name], shell, illuminated,
        selected: name === selectedSat
    });
}

// Issue #4 fix: prune satHistory keys not in current visible set
const visibleNames = new Set(sats.map(s => s.name));
Object.keys(hist).forEach(k => { if (!visibleNames.has(k)) delete hist[k]; });
global.set('satHistory', hist);

// Issue #9: AOS/LOS detection
const favorites = flow.get('favorites') || [];
const threshold = flow.get('aosThreshold') || 5;
const aosMsgs = [];
sats.forEach(s => {
    if (!favorites.includes(s.name)) return;
    const prev = prevVis[s.name] || 0;
    if (prev <= threshold && s.el > threshold) aosMsgs.push({event:'AOS', name:s.name, el:s.el, az:s.az});
});
Object.keys(prevVis).forEach(n => {
    if (favorites.includes(n) && !visibleNames.has(n)) aosMsgs.push({event:'LOS', name:n});
});
const newPrevVis = {};
sats.forEach(s => { newPrevVis[s.name] = s.el; });
global.set('prevVisible', newPrevVis);

if (aosMsgs.length > 0) {
    aosMsgs.forEach(m => {
        node.send([null, null, null, {
            payload: m.event === 'AOS'
                ? `🛰 AOS: ${m.name} — El ${m.el}° Az ${m.az}°`
                : `📡 LOS: ${m.name}`
        }]);
    });
}

sats.sort((a, b) => b.el - a.el);
const payload = {
    sats: sats.slice(0, maxSats),
    meta: {
        count: sats.length,
        tleFetchedAt,
        tleAgeMs: now - tleFetchedAt,
        observerDark,
        sunEl: +sunEl.toFixed(1),
        observer: obs,
        ts: now
    }
};

return [{payload}, {payload}, {payload}, null];

// ── helpers ────────────────────────────────────────────────────────────────
function computeSunElevation(nowMs, lat, lon) {
    const JD = nowMs / 86400000 + 2440587.5;
    const n_ = JD - 2451545.0;
    const L  = (280.460 + 0.9856474 * n_) % 360;
    const g  = (357.528 + 0.9856003 * n_) * deg2rad;
    const lam = (L + 1.915*Math.sin(g) + 0.020*Math.sin(2*g)) * deg2rad;
    const dec = Math.asin(Math.sin(23.439 * deg2rad) * Math.sin(lam));
    const UT  = (nowMs % 86400000) / 3600000;
    const HA  = ((lon + 180 + (UT - 12) * 15) % 360) * deg2rad;
    const latR = lat * deg2rad;
    return Math.asin(Math.sin(latR)*Math.sin(dec) + Math.cos(latR)*Math.cos(dec)*Math.cos(HA)) / deg2rad;
}

function isSatIlluminated(satLat, satLon, nowMs) {
    const JD = nowMs / 86400000 + 2440587.5;
    const n_ = JD - 2451545.0;
    const L  = (280.460 + 0.9856474 * n_) % 360;
    const g  = (357.528 + 0.9856003 * n_) * deg2rad;
    const lam = (L + 1.915*Math.sin(g) + 0.020*Math.sin(2*g)) * deg2rad;
    const dec  = Math.asin(Math.sin(23.439*deg2rad)*Math.sin(lam)) / deg2rad;
    const UT   = (nowMs % 86400000) / 3600000;
    const sunLon = ((180 - (UT - 12) * 15) + 360) % 360 - 180;
    // rough check: sat sub-point in sunlit hemisphere
    const dlon = (satLon - sunLon) * deg2rad;
    const cos_z = Math.sin(dec*deg2rad)*Math.sin(satLat*deg2rad) +
                  Math.cos(dec*deg2rad)*Math.cos(satLat*deg2rad)*Math.cos(dlon);
    return cos_z > 0;
}

// Issue #13: track connected Dashboard clients
let count = global.get('viewerCount') || 0;
if (msg.payload === 'connected')    count = Math.max(0, count + 1);
if (msg.payload === 'disconnected') count = Math.max(0, count - 1);
global.set('viewerCount', count);
node.status({fill: count>0?'green':'grey', shape:'dot', text:`${count} viewer(s)`});
return null;

// Store observer location from settings page
if (msg.topic === 'observer') {
    flow.set('observer', msg.payload, 'file');
    node.status({fill:'green', shape:'dot', text:`${msg.payload.lat.toFixed(3)}, ${msg.payload.lon.toFixed(3)}`});
}
if (msg.topic === 'filter') {
    flow.set('minElevation', msg.payload.minEl, 'file');
    flow.set('activeShells', msg.payload.shells, 'file');
    flow.set('maxSats', msg.payload.maxSats, 'file');
}
if (msg.topic === 'select') {
    flow.set('selectedSat', msg.payload.name);
}
if (msg.topic === 'favorites') {
    flow.set('favorites', msg.payload, 'file');
}
return null;

// Issue #11: predict next passes for selected satellite over next 6 hours
const deg2rad = Math.PI / 180;
const Re = 6371, h = 550;
const obs = flow.get('observer') || { lat: 51.0447, lon: -114.0719 };
const obs_lat = obs.lat * deg2rad;
const obs_lon = obs.lon * deg2rad;
const minEl = flow.get('minElevation') || 0;

const name = msg.payload;
const parsedSats = global.get('parsedSats') || [];
const sat = parsedSats.find(s => s.name === name);
if (!sat) { node.warn('Satellite not found: ' + name); return null; }

const { n, inc, raan, argp, M0, epoch } = sat;
const ir = inc * deg2rad;
const step = 10000; // 10s in ms
const horizon = 6 * 3600 * 1000;
const passes = [];
let inPass = false, passStart, maxEl = 0, azAtMax;

for (let dt = 0; dt <= horizon; dt += step) {
    const t = Date.now() + dt;
    const GAST = (280.46061837 + 360.98564736629 * (t - 946728000000) / 86400000) % 360;
    const M    = (M0 + n * (t - epoch) / 86400000 * 360) % 360;
    const u    = (argp + M) * deg2rad;
    const slat = Math.asin(Math.max(-1, Math.min(1, Math.sin(ir)*Math.sin(u))));
    let slon    = ((raan + Math.atan2(Math.cos(ir)*Math.sin(u), Math.cos(u))/deg2rad) - GAST + 540) % 360 - 180;
    const dlon  = slon * deg2rad - obs_lon;
    const cos_c = Math.sin(obs_lat)*Math.sin(slat) + Math.cos(obs_lat)*Math.cos(slat)*Math.cos(dlon);
    if (cos_c < Re/(Re+h)) {
        if (inPass) {
            passes.push({ los: new Date(t).toISOString(), maxEl: +maxEl.toFixed(1), azAtMax: +azAtMax.toFixed(0), aos: passStart, duration: Math.round((t - new Date(passStart).getTime())/1000) + 's' });
            inPass = false; maxEl = 0;
        }
        continue;
    }
    const c  = Math.acos(Math.max(-1, Math.min(1, cos_c)));
    const el = Math.atan((cos_c - Re/(Re+h)) / Math.sin(c)) / deg2rad;
    if (el < minEl) continue;
    const az = (Math.atan2(Math.sin(dlon)*Math.cos(slat), Math.cos(obs_lat)*Math.sin(slat)-Math.sin(obs_lat)*Math.cos(slat)*Math.cos(dlon))/deg2rad+360)%360;
    if (!inPass) { inPass = true; passStart = new Date(t).toISOString(); }
    if (el > maxEl) { maxEl = el; azAtMax = az; }
}

msg.payload = { satellite: name, passes };
return msg;
